const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const input = () => lines[idx++];
const T = parseInt(input());
for (let i = 0; i < T; i++) {
    const [n, m] = input().split(' ').map(Number);
    const grid = [];
    for (let j = 0; j < n; j++) {
        grid.push(input().split('').map(Number));
    }
    const dp = Array(n).fill().map(() => Array(m).fill(0));
    dp[0][0] = grid[0][0];
    for (let j = 1; j < n; j++) {
        dp[j][0] = dp[j-1][0] + grid[j][0];
    }
    for (let j = 1; j < m; j++) {
        dp[0][j] = dp[0][j-1] + grid[0][j];
    }
    for (let j = 1; j < n; j++) {
        for (let k = 1; k < m; k++) {
            dp[j][k] = grid[j][k] + (dp[j-1][k] < dp[j][k-1] ? dp[j-1][k] : dp[j][k-1]);
        }
    }
    console.log(dp[n-1][m-1]);
}

